import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { DualCryptoIcon } from "@/components/ui/crypto-icon";
import { useWallet } from "@/lib/walletContext";
import { liquidityPools } from "@/lib/mockData";
import { useToast } from "@/hooks/use-toast";
import { PlusCircle } from "lucide-react";

export default function LiquidityPools() {
  const { isConnected, openModal } = useWallet();
  const { toast } = useToast();

  const handleSwap = (pool: string) => {
    if (!isConnected) {
      openModal();
      return;
    }

    // In a real DeFi app, this would navigate to the swap form with the pool assets pre-selected
    toast({
      title: "Pool Selected",
      description: `Selected ${pool} pool for swapping`,
    });
  };

  const handleAddLiquidity = (pool: string) => {
    if (!isConnected) {
      openModal();
      return;
    }

    // In a real DeFi app, this would navigate to the add liquidity form with the pool pre-selected
    toast({
      title: "Add Liquidity",
      description: `Selected ${pool} pool for adding liquidity`,
    });
  };

  return (
    <Card className="bg-white shadow-sm border border-gray-100">
      <CardContent className="p-6">
        <div className="flex justify-between items-center mb-4">
          <h3 className="text-lg font-medium text-gray-900">Liquidity Pools</h3>
          <div className="flex items-center">
            <Button 
              variant="ghost"
              className="text-sm font-medium text-primary mr-4 flex items-center"
              onClick={() => {
                if (!isConnected) {
                  openModal();
                  return;
                }
                toast({
                  title: "Add Liquidity",
                  description: "Navigate to add liquidity form",
                });
              }}
            >
              <PlusCircle className="h-4 w-4 mr-1" /> Add Liquidity
            </Button>
            <span className="text-sm text-gray-500">
              Updated 1 min ago
            </span>
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-50">
              <tr>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Pool</th>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Liquidity</th>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Volume (24h)</th>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">APR</th>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Actions</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {liquidityPools.map((pool, index) => (
                <tr key={`liquidity-pool-${index}`}>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="flex items-center">
                      <DualCryptoIcon 
                        src1={pool.pair[0].icon} 
                        src2={pool.pair[1].icon} 
                        alt1={pool.pair[0].symbol} 
                        alt2={pool.pair[1].symbol}
                      />
                      <div className="ml-4">
                        <div className="text-sm font-medium text-gray-900">{pool.pair[0].symbol} / {pool.pair[1].symbol}</div>
                        <div className="text-xs text-gray-500">{pool.feeTier} fee tier</div>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="text-sm font-mono">
                      ${(pool.liquidity / 1000000).toFixed(1)}M
                    </div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="text-sm font-mono">
                      ${(pool.volume24h / 1000000).toFixed(1)}M
                    </div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="text-sm text-success font-medium">{pool.apy}%</div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm font-medium">
                    <button 
                      className="text-primary hover:text-blue-700 mr-3"
                      onClick={() => handleSwap(`${pool.pair[0].symbol}/${pool.pair[1].symbol}`)}
                    >
                      Swap
                    </button>
                    <button 
                      className="text-secondary hover:text-green-700"
                      onClick={() => handleAddLiquidity(`${pool.pair[0].symbol}/${pool.pair[1].symbol}`)}
                    >
                      Add
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </CardContent>
    </Card>
  );
}

client/src/components/price-ticker.tsx.content:
import { useState, useEffect } from 'react';
import { usePriceFeed, useMultiplePriceFeeds } from '@/hooks/use-price-feed';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Skeleton } from '@/components/ui/skeleton';
import { 
  TrendingUp, 
  TrendingDown, 
  RefreshCw, 
  Clock,
  Wifi,
  WifiOff,
  Activity
} from 'lucide-react';

interface PriceTickerProps {
  symbol: string;
  showDetails?: boolean;
  compact?: boolean;
}

export function PriceTicker({ symbol, showDetails = false, compact = false }: PriceTickerProps) {
  const { price, loading, error, lastUpdated, refresh, isStale } = usePriceFeed(symbol, {
    enableAutoRefresh: true,
    refreshInterval: 30000
  });

  const formatPrice = (price: number) => {
    if (price >= 1) {
      return `$${price.toLocaleString('en-US', { 
        minimumFractionDigits: 2, 
        maximumFractionDigits: 2 
      })}`;
    } else {
      return `$${price.toFixed(6)}`;
    }
  };

  const formatChange = (change: number) => {
    const sign = change >= 0 ? '+' : '';
    return `${sign}${change.toFixed(2)}%`;
  };

  const getChangeColor = (change: number) => {
    if (change > 0) return 'text-green-600 dark:text-green-400';
    if (change < 0) return 'text-red-600 dark:text-red-400';
    return 'text-gray-600 dark:text-gray-400';
  };

  const getChangeIcon = (change: number) => {
    if (change > 0) return <TrendingUp className="h-4 w-4" />;
    if (change < 0) return <TrendingDown className="h-4 w-4" />;
    return null;
  };

  if (loading) {
    return (
      <div className={compact ? "flex items-center space-x-2" : ""}>
        <Skeleton className={compact ? "h-6 w-20" : "h-8 w-24"} />
        <Skeleton className={compact ? "h-4 w-16" : "h-6 w-20"} />
      </div>
    );
  }

  if (error || !price) {
    return (
      <div className={`flex items-center space-x-2 ${compact ? 'text-sm' : ''}`}>
        <WifiOff className="h-4 w-4 text-red-500" />
        <span className="text-red-600 dark:text-red-400">
          {error || 'Price unavailable'}
        </span>
        <Button
          variant="ghost"
          size="sm"
          onClick={refresh}
          className="h-6 w-6 p-0"
        >
          <RefreshCw className="h-3 w-3" />
        </Button>
      </div>
    );
  }

  if (compact) {
    return (
      <div className="flex items-center space-x-2">
        <div className="flex items-center space-x-1">
          <span className="font-semibold text-sm">{formatPrice(price.price)}</span>
          <div className={`flex items-center space-x-1 ${getChangeColor(price.change24h)}`}>
            {getChangeIcon(price.change24h)}
            <span className="text-xs">{formatChange(price.change24h)}</span>
          </div>
        </div>
        <div className="flex items-center space-x-1">
          {isStale ? (
            <WifiOff className="h-3 w-3 text-orange-500" />
          ) : (
            <Wifi className="h-3 w-3 text-green-500" />
          )}
        </div>
      </div>
    );
  }

  return (
    <Card className="w-full">
      <CardHeader className="pb-2">
        <div className="flex items-center justify-between">
          <CardTitle className="text-lg font-bold">{symbol.toUpperCase()}</CardTitle>
          <div className="flex items-center space-x-2">
            <Badge variant={isStale ? "destructive" : "secondary"} className="text-xs">
              {isStale ? "Stale" : "Live"}
            </Badge>
            <Button
              variant="ghost"
              size="sm"
              onClick={refresh}
              className="h-6 w-6 p-0"
            >
              <RefreshCw className="h-3 w-3" />
            </Button>
          </div>
        </div>
      </CardHeader>
      <CardContent>
        <div className="space-y-4">
          <div className="flex items-center justify-between">
            <div className="text-2xl font-bold">{formatPrice(price.price)}</div>
            <div className={`flex items-center space-x-1 ${getChangeColor(price.change24h)}`}>
              {getChangeIcon(price.change24h)}
              <span className="text-lg font-semibold">{formatChange(price.change24h)}</span>
            </div>
          </div>

          {showDetails && (
            <div className="space-y-2 text-sm">
              <div className="flex justify-between">
                <span className="text-muted-foreground">24h Volume:</span>
                <span className="font-medium">
                  ${price.volume24h.toLocaleString('en-US', { maximumFractionDigits: 0 })}
                </span>
              </div>
              <div className="flex justify-between">
                <span className="text-muted-foreground">Confidence:</span>
                <span className="font-medium">{(price.confidence * 100).toFixed(1)}%</span>
              </div>
              <div className="flex justify-between">
                <span className="text-muted-foreground">Source:</span>
                <span className="font-medium">{price.source}</span>
              </div>
              {lastUpdated && (
                <div className="flex justify-between items-center">
                  <span className="text-muted-foreground">Last Updated:</span>
                  <div className="flex items-center space-x-1">
                    <Clock className="h-3 w-3" />
                    <span className="font-medium">{lastUpdated.toLocaleTimeString()}</span>
                  </div>
                </div>
              )}
            </div>
          )}
        </div>
      </CardContent>
    </Card>
  );
}

interface MarketOverviewProps {
  symbols: string[];
}

export function MarketOverview({ symbols }: MarketOverviewProps) {
  const { prices, loading, errors, refresh } = useMultiplePriceFeeds(symbols, {
    enableAutoRefresh: true,
    refreshInterval: 30000
  });

  if (loading) {
    return (
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center space-x-2">
            <Activity className="h-5 w-5" />
            <span>Market Overview</span>
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="space-y-3">
            {symbols.map(symbol => (
              <div key={symbol} className="flex items-center justify-between">
                <Skeleton className="h-4 w-16" />
                <Skeleton className="h-4 w-20" />
                <Skeleton className="h-4 w-16" />
              </div>
            ))}
          </div>
        </CardContent>
      </Card>
    );
  }

  return (
    <Card>
      <CardHeader>
        <div className="flex items-center justify-between">
          <CardTitle className="flex items-center space-x-2">
            <Activity className="h-5 w-5" />
            <span>Market Overview</span>
          </CardTitle>
          <Button
            variant="ghost"
            size="sm"
            onClick={refresh}
            className="h-6 w-6 p-0"
          >
            <RefreshCw className="h-3 w-3" />
          </Button>
        </div>
      </CardHeader>
      <CardContent>
        <div className="space-y-3">
          {symbols.map(symbol => {
            const price = prices.get(symbol);
            const error = errors.get(symbol);

            if (error) {
              return (
                <div key={symbol} className="flex items-center justify-between">
                  <span className="font-medium">{symbol.toUpperCase()}</span>
                  <span className="text-red-600 dark:text-red-400 text-sm">{error}</span>
                </div>
              );
            }

            if (!price) {
              return (
                <div key={symbol} className="flex items-center justify-between">
                  <Skeleton className="h-4 w-16" />
                  <Skeleton className="h-4 w-20" />
                  <Skeleton className="h-4 w-16" />
                </div>
              );
            }

            return (
              <div key={symbol} className="flex items-center justify-between">
                <span className="font-medium">{symbol.toUpperCase()}</span>
                <span className="font-mono">
                  {price.price >= 1 
                    ? `$${price.price.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`
                    : `$${price.price.toFixed(6)}`
                  }
                </span>
                <div className={`flex items-center space-x-1 ${
                  price.change24h > 0 
                    ? 'text-green-600 dark:text-green-400' 
                    : price.change24h < 0 
                    ? 'text-red-600 dark:text-red-400'
                    : 'text-gray-600 dark:text-gray-400'
                }`}>
                  {price.change24h > 0 && <TrendingUp className="h-3 w-3" />}
                  {price.change24h < 0 && <TrendingDown className="h-3 w-3" />}
                  <span className="text-sm">
                    {price.change24h >= 0 ? '+' : ''}{price.change24h.toFixed(2)}%
                  </span>
                </div>
              </div>
            );
          })}
        </div>
      </CardContent>
    </Card>
  );
}

client/src/components/settings-modal.tsx.content:
import { useState } from "react";
import { useLocation } from "wouter";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Switch } from "@/components/ui/switch";
import { useSettings, ThemeType, ColorScheme } from "@/lib/settingsContext";
import { useAuth } from "@/hooks/use-auth";
import { useToast } from "@/hooks/use-toast";
import { Moon, Sun, Laptop, User, Bell, ShieldCheck, Palette, LogOut } from "lucide-react";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";

export default function SettingsModal() {
  const { 
    isSettingsOpen, 
    closeSettings, 
    theme, 
    setTheme, 
    colorScheme, 
    setColorScheme,
    userProfile,
    updateProfile
  } = useSettings();
  const { user, logoutMutation } = useAuth();
  const [, setLocation] = useLocation();
  const { toast } = useToast();
  const [activeTab, setActiveTab] = useState("profile");
  const [displayName, setDisplayName] = useState(userProfile.displayName || "");
  const [email, setEmail] = useState(userProfile.email || "");
  const [notificationsEnabled, setNotificationsEnabled] = useState(userProfile.notificationsEnabled);

  const handleLogout = async () => {
    try {
      await logoutMutation.mutateAsync();
      closeSettings();
      setLocation('/auth');
      toast({
        title: "Logged Out",
        description: "You have been successfully logged out",
      });
    } catch (error) {
      toast({
        title: "Logout Failed",
        description: "Failed to logout. Please try again.",
        variant: "destructive",
      });
    }
  };

  const handleSaveProfile = () => {
    updateProfile({
      displayName: displayName || null,
      email: email || null
    });

    toast({
      title: "Profile Updated",
      description: "Your profile information has been saved",
    });
  };

  const handleSaveNotifications = () => {
    updateProfile({
      notificationsEnabled
    });

    toast({
      title: "Notification Settings Updated",
      description: notificationsEnabled 
        ? "You will receive notifications about important events" 
        : "Notifications are now disabled",
    });
  };

  const themeOptions: {value: ThemeType, label: string, icon: JSX.Element}[] = [
    { value: 'light', label: 'Light', icon: <Sun className="h-4 w-4 mr-2" /> },
    { value: 'dark', label: 'Dark', icon: <Moon className="h-4 w-4 mr-2" /> },
    { value: 'system', label: 'System', icon: <Laptop className="h-4 w-4 mr-2" /> }
  ];

  const colorOptions: {value: ColorScheme, label: string, color: string}[] = [
    { value: 'blue', label: 'Blue', color: 'bg-blue-500' },
    { value: 'purple', label: 'Purple', color: 'bg-purple-500' },
    { value: 'emerald', label: 'Emerald', color: 'bg-emerald-500' },
    { value: 'orange', label: 'Orange', color: 'bg-orange-500' },
    { value: 'indigo', label: 'Indigo', color: 'bg-indigo-500' }
  ];

  return (
    <Dialog open={isSettingsOpen} onOpenChange={closeSettings}>
      <DialogContent className="sm:max-w-md">
        <DialogHeader>
          <DialogTitle className="text-2xl font-bold text-gray-900">Settings</DialogTitle>
          <DialogDescription className="text-gray-600 mt-2">
            Customize your experience and manage your account settings.
          </DialogDescription>
        </DialogHeader>

        <Tabs defaultValue="profile" className="w-full" value={activeTab} onValueChange={setActiveTab}>
          <TabsList className="grid grid-cols-4 mb-4">
            <TabsTrigger value="profile" className="flex items-center justify-center">
              <User className="h-4 w-4 mr-2" />
              <span>Profile</span>
            </TabsTrigger>
            <TabsTrigger value="appearance" className="flex items-center justify-center">
              <Palette className="h-4 w-4 mr-2" />
              <span>Appearance</span>
            </TabsTrigger>
            <TabsTrigger value="notifications" className="flex items-center justify-center">
              <Bell className="h-4 w-4 mr-2" />
              <span>Notifications</span>
            </TabsTrigger>
            <TabsTrigger value="security" className="flex items-center justify-center">
              <ShieldCheck className="h-4 w-4 mr-2" />
              <span>Security</span>
            </TabsTrigger>
          </TabsList>

          <TabsContent value="profile" className="space-y-4">
            <div className="flex items-center justify-center mb-6">
              <div className="relative">
                <Avatar className="h-20 w-20">
                  <AvatarImage src={userProfile.avatar || ""} />
                  <AvatarFallback className="bg-primary text-white text-lg">
                    {user?.username ? user.username.charAt(0).toUpperCase() : "U"}
                  </AvatarFallback>
                </Avatar>
              </div>
            </div>

            <div className="text-center space-y-2 mb-6">
              <h3 className="text-xl font-semibold">Welcome back!</h3>
              <p className="text-muted-foreground">
                Logged in as: <span className="font-medium text-foreground">{user?.username}</span>
              </p>
            </div>

            <div className="space-y-4">
              <div className="p-4 border rounded-lg bg-muted/50">
                <div className="flex items-center justify-between">
                  <div>
                    <h4 className="font-medium">Account Information</h4>
                    <p className="text-sm text-muted-foreground">Username: {user?.username}</p>
                    <p className="text-sm text-muted-foreground">Role: {user?.role || 'User'}</p>
                  </div>
                  <User className="h-8 w-8 text-muted-foreground" />
                </div>
              </div>

              <Button 
                className="w-full" 
                variant="destructive"
                onClick={handleLogout}
                disabled={logoutMutation.isPending}
              >
                <LogOut className="h-4 w-4 mr-2" />
                {logoutMutation.isPending ? "Logging out..." : "Logout"}
              </Button>
            </div>
          </TabsContent>

          <TabsContent value="appearance" className="space-y-4">
            <div className="space-y-2">
              <Label className="block mb-2">Theme</Label>
              <div className="grid grid-cols-3 gap-2">
                {themeOptions.map((option) => (
                  <Button
                    key={option.value}
                    type="button"
                    variant={theme === option.value ? "default" : "outline"}
                    className={`flex items-center justify-center h-12 ${theme === option.value ? 'border-2 border-primary' : ''}`}
                    onClick={() => {
                      setTheme(option.value);
                      toast({
                        title: "Theme Updated",
                        description: `Theme changed to ${option.label} mode`,
                      });
                    }}
                  >
                    {option.icon}
                    {option.label}
                  </Button>
                ))}
              </div>
            </div>

            <div className="space-y-2">
              <Label className="block mb-2">Accent Color</Label>
              <div className="grid grid-cols-5 gap-2">
                {colorOptions.map((option) => (
                  <button
                    key={option.value}
                    type="button"
                    className={`h-10 rounded-full ${option.color} ${colorScheme === option.value ? 'ring-2 ring-offset-2 ring-gray-500' : ''}`}
                    onClick={() => {
                      setColorScheme(option.value);
                      toast({
                        title: "Color Updated",
                        description: `Accent color changed to ${option.label}`,
                      });
                    }}
                    title={option.label}
                  />
                ))}
              </div>
            </div>
          </TabsContent>

          <TabsContent value="notifications" className="space-y-4">
            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <div>
                  <h4 className="text-sm font-medium">Enable Notifications</h4>
                  <p className="text-sm text-gray-500">Receive alerts for important events</p>
                </div>
                <Switch 
                  checked={notificationsEnabled}
                  onCheckedChange={setNotificationsEnabled}
                />
              </div>

              <div className="flex items-center justify-between">
                <div>
                  <h4 className="text-sm font-medium">Transaction Alerts</h4>
                  <p className="text-sm text-gray-500">Get notified about your DeFi transactions</p>
                </div>
                <Switch 
                  checked={notificationsEnabled} 
                  disabled={!notificationsEnabled}
                  onCheckedChange={() => {}}
                />
              </div>

              <div className="flex items-center justify-between">
                <div>
                  <h4 className="text-sm font-medium">Price Alerts</h4>
                  <p className="text-sm text-gray-500">Alerts when assets reach price targets</p>
                </div>
                <Switch 
                  checked={notificationsEnabled} 
                  disabled={!notificationsEnabled}
                  onCheckedChange={() => {}}
                />
              </div>

              <div className="flex items-center justify-between">
                <div>
                  <h4 className="text-sm font-medium">Security Alerts</h4>
                  <p className="text-sm text-gray-500">Important security notifications</p>
                </div>
                <Switch 
                  checked={true} 
                  disabled
                  onCheckedChange={() => {}}
                />
              </div>

              <Button 
                className="w-full mt-4" 
                onClick={handleSaveNotifications}
              >
                Save Notification Settings
              </Button>
            </div>
          </TabsContent>

          <TabsContent value="security" className="space-y-4">
            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <div>
                  <h4 className="text-sm font-medium">Two-Factor Authentication</h4>
                  <p className="text-sm text-gray-500">Add an extra layer of security to your account</p>
                </div>
                <Switch 
                  checked={false}
                  onCheckedChange={() => {
                    toast({
                      title: "2FA Setup",
                      description: "Two-factor authentication setup would be initiated here",
                    });
                  }}
                />
              </div>

              <div className="flex items-center justify-between">
                <div>
                  <h4 className="text-sm font-medium">Transaction Signing</h4>
                  <p className="text-sm text-gray-500">Require password for all transactions</p>
                </div>
                <Switch 
                  checked={true}
                  onCheckedChange={() => {}}
                />
              </div>

              <div className="flex items-center justify-between">
                <div>
                  <h4 className="text-sm font-medium">Hardware Wallet Support</h4>
                  <p className="text-sm text-gray-500">Enable hardware wallet integration</p>
                </div>
                <Switch 
                  checked={true}
                  onCheckedChange={() => {}}
                />
              </div>

              <div className="flex items-center justify-between">
                <div>
                  <h4 className="text-sm font-medium">Spending Limits</h4>
                  <p className="text-sm text-gray-500">Set daily transaction limits</p>
                </div>
                <Input 
                  type="number"
                  className="w-24"
                  placeholder="1000"
                  onChange={() => {
                    toast({
                      title: "Limit Updated",
                      description: "Daily spending limit would be updated here",
                    });
                  }}
                />
              </div>

              <div className="space-y-2 mt-6">
                <h4 className="text-sm font-medium">Active Sessions</h4>
                <div className="bg-gray-50 dark:bg-gray-800 p-3 rounded-lg">
                  <div className="flex items-center justify-between">
                    <div>
                      <p className="text-sm font-medium">Current Browser</p>
                      <p className="text-xs text-gray-500">Last active: Just now</p>
                    </div>
                    <Button variant="outline" size="sm">
                      Current
                    </Button>
                  </div>
                </div>
              </div>

              <Button 
                className="w-full mt-4" 
                onClick={() => {
                  toast({
                    title: "Security Settings",
                    description: "Security settings would be saved here",
                  });
                }}
              >
                Save Security Settings
              </Button>
            </div>
          </TabsContent>
        </Tabs>
      </DialogContent>
    </Dialog>
  );
}

