import { useState, useEffect } from "react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Switch } from "@/components/ui/switch";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { 
  Share, 
  Trophy, 
  TrendingUp, 
  Eye, 
  EyeOff, 
  Copy, 
  Twitter, 
  MessageCircle,
  Star,
  Award,
  Target,
  Zap,
  Shield
} from "lucide-react";
import { useToast } from "@/hooks/use-toast";

interface Achievement {
  id: string;
  type: 'milestone' | 'streak' | 'profit' | 'portfolio' | 'trading';
  title: string;
  description: string;
  icon: JSX.Element;
  value: number;
  metric: string;
  achievedAt: Date;
  rarity: 'common' | 'rare' | 'epic' | 'legendary';
  isPublic: boolean;
}

interface SocialPost {
  id: string;
  achievementId: string;
  customMessage: string;
  privacyLevel: 'public' | 'friends' | 'private';
  showAmount: boolean;
  showPercentage: boolean;
  showPortfolioValue: boolean;
  createdAt: Date;
}

interface SocialSharingProps {
  userAchievements?: Achievement[];
  portfolioValue?: number;
  totalProfit?: number;
  profitPercentage?: number;
}

export default function SocialSharing({ 
  userAchievements = [],
  portfolioValue = 0,
  totalProfit = 0,
  profitPercentage = 0
}: SocialSharingProps) {
  const { toast } = useToast();
  const [achievements, setAchievements] = useState<Achievement[]>([]);
  const [selectedAchievement, setSelectedAchievement] = useState<Achievement | null>(null);
  const [showShareDialog, setShowShareDialog] = useState(false);
  const [shareSettings, setShareSettings] = useState({
    privacyLevel: 'public' as 'public' | 'friends' | 'private',
    showAmount: false,
    showPercentage: true,
    showPortfolioValue: false,
    customMessage: ''
  });

  useEffect(() => {
    // Generate achievements based on user data
    const generatedAchievements = generateAchievements(portfolioValue, totalProfit, profitPercentage);
    setAchievements([...userAchievements, ...generatedAchievements]);
  }, [userAchievements, portfolioValue, totalProfit, profitPercentage]);

  const generateAchievements = (portfolio: number, profit: number, percentage: number): Achievement[] => {
    const achievements: Achievement[] = [];

    // Portfolio milestones
    if (portfolio >= 1000) {
      achievements.push({
        id: 'portfolio_1k',
        type: 'milestone',
        title: 'First Thousand',
        description: 'Reached $1,000 portfolio value',
        icon: <Trophy className="h-5 w-5" />,
        value: portfolio,
        metric: 'USD',
        achievedAt: new Date(),
        rarity: 'common',
        isPublic: true
      });
    }

    if (portfolio >= 10000) {
      achievements.push({
        id: 'portfolio_10k',
        type: 'milestone',
        title: 'Rising Star',
        description: 'Reached $10,000 portfolio value',
        icon: <Star className="h-5 w-5" />,
        value: portfolio,
        metric: 'USD',
        achievedAt: new Date(),
        rarity: 'rare',
        isPublic: true
      });
    }

    // Profit achievements
    if (percentage >= 10) {
      achievements.push({
        id: 'profit_10_percent',
        type: 'profit',
        title: 'Profit Master',
        description: 'Achieved 10%+ returns',
        icon: <TrendingUp className="h-5 w-5" />,
        value: percentage,
        metric: '%',
        achievedAt: new Date(),
        rarity: 'rare',
        isPublic: true
      });
    }

    if (percentage >= 50) {
      achievements.push({
        id: 'profit_50_percent',
        type: 'profit',
        title: 'DeFi Legend',
        description: 'Achieved 50%+ returns',
        icon: <Award className="h-5 w-5" />,
        value: percentage,
        metric: '%',
        achievedAt: new Date(),
        rarity: 'legendary',
        isPublic: true
      });
    }

    return achievements;
  };

  const getRarityColor = (rarity: string) => {
    switch (rarity) {
      case 'common': return 'bg-gray-100 text-gray-800 border-gray-300';
      case 'rare': return 'bg-blue-100 text-blue-800 border-blue-300';
      case 'epic': return 'bg-purple-100 text-purple-800 border-purple-300';
      case 'legendary': return 'bg-yellow-100 text-yellow-800 border-yellow-300';
      default: return 'bg-gray-100 text-gray-800 border-gray-300';
    }
  };

  const generateShareContent = (achievement: Achievement) => {
    const baseMessage = `🎉 Just unlocked "${achievement.title}" on my DeFi journey!`;
    const details = [];

    if (shareSettings.showPercentage && achievement.type === 'profit') {
      details.push(`📈 ${achievement.value}${achievement.metric} returns`);
    }

    if (shareSettings.showAmount && achievement.type === 'milestone') {
      details.push(`💰 $${achievement.value.toLocaleString()} portfolio value`);
    }

    if (shareSettings.showPortfolioValue && portfolioValue > 0) {
      details.push(`🏦 Total portfolio: $${portfolioValue.toLocaleString()}`);
    }

    const customPart = shareSettings.customMessage ? `\n\n${shareSettings.customMessage}` : '';
    const detailsPart = details.length > 0 ? `\n${details.join('\n')}` : '';

    return `${baseMessage}${detailsPart}${customPart}\n\n#DeFi #CryptoAchievements #InvestmentGoals`;
  };

  const handleShare = async (platform: 'twitter' | 'copy' | 'general') => {
    if (!selectedAchievement) return;

    const content = generateShareContent(selectedAchievement);

    try {
      if (platform === 'copy') {
        await navigator.clipboard.writeText(content);
        toast({
          title: "Copied to Clipboard",
          description: "Share content copied successfully!",
        });
      } else if (platform === 'twitter') {
        const twitterUrl = `https://twitter.com/intent/tweet?text=${encodeURIComponent(content)}`;
        window.open(twitterUrl, '_blank');
        toast({
          title: "Opening Twitter",
          description: "Share your achievement on Twitter!",
        });
      } else {
        if (navigator.share) {
          await navigator.share({
            title: selectedAchievement.title,
            text: content,
          });
          toast({
            title: "Shared Successfully",
            description: "Your achievement has been shared!",
          });
        } else {
          await navigator.clipboard.writeText(content);
          toast({
            title: "Copied to Clipboard",
            description: "Share content copied successfully!",
          });
        }
      }
      setShowShareDialog(false);
    } catch (error) {
      toast({
        title: "Share Failed",
        description: "Unable to share at this time",
        variant: "destructive",
      });
    }
  };

  const toggleAchievementPrivacy = (achievementId: string) => {
    setAchievements(prev => 
      prev.map(ach => 
        ach.id === achievementId 
          ? { ...ach, isPublic: !ach.isPublic }
          : ach
      )
    );
  };

  return (
    <div className="space-y-6">
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center">
            <Share className="h-5 w-5 mr-2" />
            Investment Achievements
          </CardTitle>
          <CardDescription>
            Share your DeFi milestones and trading successes with privacy controls
          </CardDescription>
        </CardHeader>
        <CardContent>
          <div className="grid gap-4">
            {achievements.length === 0 ? (
              <div className="text-center py-8 text-muted-foreground">
                <Target className="h-12 w-12 mx-auto mb-4 opacity-50" />
                <p>Start trading to unlock achievements!</p>
                <p className="text-sm">Complete your first transaction to earn your first badge.</p>
              </div>
            ) : (
              achievements.map((achievement) => (
                <Card key={achievement.id} className="relative overflow-hidden">
                  <CardContent className="p-4">
                    <div className="flex items-center justify-between">
                      <div className="flex items-center space-x-3">
                        <div className={`p-2 rounded-full ${getRarityColor(achievement.rarity)}`}>
                          {achievement.icon}
                        </div>
                        <div>
                          <h4 className="font-semibold flex items-center space-x-2">
                            {achievement.title}
                            <Badge className={getRarityColor(achievement.rarity)}>
                              {achievement.rarity}
                            </Badge>
                          </h4>
                          <p className="text-sm text-muted-foreground">
                            {achievement.description}
                          </p>
                          <div className="flex items-center space-x-2 mt-1">
                            <span className="text-lg font-bold text-green-600">
                              {achievement.value.toLocaleString()}{achievement.metric}
                            </span>
                            <span className="text-xs text-muted-foreground">
                              {achievement.achievedAt.toLocaleDateString()}
                            </span>
                          </div>
                        </div>
                      </div>
                      <div className="flex items-center space-x-2">
                        <Button
                          variant="ghost"
                          size="sm"
                          onClick={() => toggleAchievementPrivacy(achievement.id)}
                          className="text-muted-foreground"
                        >
                          {achievement.isPublic ? (
                            <Eye className="h-4 w-4" />
                          ) : (
                            <EyeOff className="h-4 w-4" />
                          )}
                        </Button>
                        <Button
                          size="sm"
                          onClick={() => {
                            setSelectedAchievement(achievement);
                            setShowShareDialog(true);
                          }}
                          disabled={!achievement.isPublic}
                        >
                          <Share className="h-4 w-4 mr-2" />
                          Share
                        </Button>
                      </div>
                    </div>
                  </CardContent>
                </Card>
              ))
            )}
          </div>
        </CardContent>
      </Card>

      {/* Share Dialog */}
      <Dialog open={showShareDialog} onOpenChange={setShowShareDialog}>
        <DialogContent className="sm:max-w-[500px]">
          <DialogHeader>
            <DialogTitle className="flex items-center">
              <Share className="h-5 w-5 mr-2" />
              Share Achievement
            </DialogTitle>
            <DialogDescription>
              Customize your share settings and privacy controls
            </DialogDescription>
          </DialogHeader>

          {selectedAchievement && (
            <div className="space-y-6">
              {/* Achievement Preview */}
              <Card className="bg-gradient-to-r from-blue-50 to-purple-50 dark:from-blue-950/20 dark:to-purple-950/20">
                <CardContent className="p-4">
                  <div className="flex items-center space-x-3">
                    <div className={`p-2 rounded-full ${getRarityColor(selectedAchievement.rarity)}`}>
                      {selectedAchievement.icon}
                    </div>
                    <div>
                      <h4 className="font-semibold">{selectedAchievement.title}</h4>
                      <p className="text-sm text-muted-foreground">
                        {selectedAchievement.description}
                      </p>
                    </div>
                  </div>
                </CardContent>
              </Card>

              {/* Privacy Settings */}
              <div className="space-y-4">
                <h4 className="font-medium flex items-center">
                  <Shield className="h-4 w-4 mr-2" />
                  Privacy Settings
                </h4>

                <div className="space-y-3">
                  <div className="flex items-center justify-between">
                    <Label htmlFor="show-percentage">Show percentage returns</Label>
                    <Switch
                      id="show-percentage"
                      checked={shareSettings.showPercentage}
                      onCheckedChange={(checked) => 
                        setShareSettings(prev => ({ ...prev, showPercentage: checked }))
                      }
                    />
                  </div>

                  <div className="flex items-center justify-between">
                    <Label htmlFor="show-amount">Show dollar amounts</Label>
                    <Switch
                      id="show-amount"
                      checked={shareSettings.showAmount}
                      onCheckedChange={(checked) => 
                        setShareSettings(prev => ({ ...prev, showAmount: checked }))
                      }
                    />
                  </div>

                  <div className="flex items-center justify-between">
                    <Label htmlFor="show-portfolio">Show total portfolio value</Label>
                    <Switch
                      id="show-portfolio"
                      checked={shareSettings.showPortfolioValue}
                      onCheckedChange={(checked) => 
                        setShareSettings(prev => ({ ...prev, showPortfolioValue: checked }))
                      }
                    />
                  </div>
                </div>

                <div className="space-y-2">
                  <Label htmlFor="privacy-level">Visibility</Label>
                  <Select 
                    value={shareSettings.privacyLevel} 
                    onValueChange={(value: 'public' | 'friends' | 'private') => 
                      setShareSettings(prev => ({ ...prev, privacyLevel: value }))
                    }
                  >
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="public">Public - Anyone can see</SelectItem>
                      <SelectItem value="friends">Friends only</SelectItem>
                      <SelectItem value="private">Private - Just me</SelectItem>
                    </SelectContent>
                  </Select>
                </div>

                <div className="space-y-2">
                  <Label htmlFor="custom-message">Custom message (optional)</Label>
                  <Textarea
                    id="custom-message"
                    placeholder="Add your own message..."
                    value={shareSettings.customMessage}
                    onChange={(e) => 
                      setShareSettings(prev => ({ ...prev, customMessage: e.target.value }))
                    }
                    rows={3}
                  />
                </div>
              </div>

              {/* Preview */}
              <div className="space-y-2">
                <Label>Share Preview</Label>
                <Card className="p-3 bg-muted/50">
                  <pre className="text-sm whitespace-pre-wrap font-sans">
                    {generateShareContent(selectedAchievement)}
                  </pre>
                </Card>
              </div>

              {/* Share Buttons */}
              <div className="flex justify-end space-x-2">
                <Button variant="outline" onClick={() => setShowShareDialog(false)}>
                  Cancel
                </Button>
                <Button
                  variant="outline"
                  onClick={() => handleShare('copy')}
                  className="flex items-center space-x-2"
                >
                  <Copy className="h-4 w-4" />
                  <span>Copy</span>
                </Button>
                <Button
                  variant="outline"
                  onClick={() => handleShare('twitter')}
                  className="flex items-center space-x-2 text-blue-600"
                >
                  <Twitter className="h-4 w-4" />
                  <span>Twitter</span>
                </Button>
                <Button
                  onClick={() => handleShare('general')}
                  className="flex items-center space-x-2"
                >
                  <Share className="h-4 w-4" />
                  <span>Share</span>
                </Button>
              </div>
            </div>
          )}
        </DialogContent>
      </Dialog>
    </div>
  );
}

client/src/components/swap-form.tsx.content:
import { useState, useEffect } from "react";
import { useWallet } from "@/lib/walletContext";
import { Card, CardContent } from "@/components/ui/card";
import { Label } from "@/components/ui/label";
import { Button } from "@/components/ui/button";
import { useToast } from "@/hooks/use-toast";
import { assets, getExchangeRate, calculatePriceImpact } from "@/lib/mockData";
import { Asset } from "@/lib/mockData";
import { 
  ArrowUpDown, 
  RefreshCw, 
  Zap, 
  AlertCircle, 
  Percent,
  ChevronDown
} from "lucide-react";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Input } from "@/components/ui/input";

export default function SwapForm() {
  const { isConnected, openModal } = useWallet();
  const { toast } = useToast();
  const [fromAsset, setFromAsset] = useState<Asset | null>(null);
  const [toAsset, setToAsset] = useState<Asset | null>(null);
  const [fromAmount, setFromAmount] = useState("");
  const [toAmount, setToAmount] = useState("");
  const [exchangeRate, setExchangeRate] = useState<number | null>(null);
  const [priceImpact, setPriceImpact] = useState<number>(0);

  const handleFromAssetChange = (value: string) => {
    const asset = assets.find(a => a.symbol === value);
    if (asset) {
      setFromAsset(asset);
      updateCalculations(fromAmount, asset, toAsset);
    }
  };

  const handleToAssetChange = (value: string) => {
    const asset = assets.find(a => a.symbol === value);
    if (asset) {
      setToAsset(asset);
      updateCalculations(fromAmount, fromAsset, asset);
    }
  };

  const updateCalculations = (amount: string, from: Asset | null, to: Asset | null) => {
    if (from && to && amount && !isNaN(parseFloat(amount))) {
      const rate = getExchangeRate(from, to);
      setExchangeRate(rate);

      const fromAmountNum = parseFloat(amount);
      setToAmount((fromAmountNum * rate).toFixed(6));

      const impact = calculatePriceImpact(fromAmountNum, from);
      setPriceImpact(impact);
    } else {
      setToAmount("");
      setExchangeRate(null);
      setPriceImpact(0);
    }
  };

  const handleFromAmountChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value;
    setFromAmount(value);
    updateCalculations(value, fromAsset, toAsset);
  };

  const switchAssets = () => {
    const tempFromAsset = fromAsset;
    const tempToAsset = toAsset;
    const tempFromAmount = fromAmount;
    const tempToAmount = toAmount;

    setFromAsset(tempToAsset);
    setToAsset(tempFromAsset);
    setFromAmount(tempToAmount);
    setToAmount(tempFromAmount);

    updateCalculations(tempToAmount, tempToAsset, tempFromAsset);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (!isConnected) {
      openModal();
      return;
    }

    if (!fromAsset || !toAsset || !fromAmount || parseFloat(fromAmount) <= 0) {
      toast({
        title: "Invalid Input",
        description: "Please select assets and enter a valid amount",
        variant: "destructive",
      });
      return;
    }

    // In a real DeFi app, this would interact with a smart contract
    toast({
      title: "Transaction Submitted",
      description: `Swapping ${fromAmount} ${fromAsset.symbol} for approximately ${toAmount} ${toAsset.symbol}`,
    });
  };

  // Set default assets on load
  useEffect(() => {
    const defaultFromAsset = assets.find(a => a.symbol === "ETH");
    const defaultToAsset = assets.find(a => a.symbol === "USDC");

    if (defaultFromAsset && defaultToAsset) {
      setFromAsset(defaultFromAsset);
      setToAsset(defaultToAsset);
      setExchangeRate(getExchangeRate(defaultFromAsset, defaultToAsset));
    }
  }, []);

  return (
    <div className="card-shadow hover:shadow-md transition-all duration-300">
      <Card className="bg-white border border-gray-100 overflow-hidden">
        <div className="bg-gradient-to-r from-emerald-600 to-teal-600 py-4 px-6">
          <h3 className="text-lg font-bold text-white flex items-center">
            <RefreshCw className="mr-2 h-5 w-5" />
            Token Swap
          </h3>
          <p className="text-sm text-emerald-100">
            Instantly exchange tokens at the best rates
          </p>
        </div>

        <CardContent className="p-6">
          {!isConnected && (
            <div className="mb-6 bg-blue-50 border border-blue-200 rounded-lg p-4 flex items-center">
              <AlertCircle className="h-5 w-5 text-blue-600 mr-2 flex-shrink-0" />
              <div className="flex-1">
                <p className="text-blue-700 text-sm font-medium">Connect your wallet to swap tokens</p>
                <p className="text-blue-600 text-xs mt-1">You need to connect your wallet first to access swapping</p>
              </div>
              <Button 
                className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg text-sm font-medium ml-4 btn-hover-effect"
                onClick={() => openModal()}
              >
                Connect Wallet
              </Button>
            </div>
          )}

          <form onSubmit={handleSubmit}>
            <div className="mb-4">
              <Label className="block text-sm font-medium text-gray-700 mb-1 flex items-center">
                <span className="mr-1">You Pay</span>
                <div className="text-xs bg-emerald-100 text-emerald-700 px-2 py-0.5 rounded-full">From</div>
              </Label>
              <div className="bg-gray-50 rounded-lg p-4 border border-gray-200 hover:border-emerald-300 transition-colors">
                <div className="flex justify-between items-center mb-2">
                  <div className="relative w-2/3">
                    <Input
                      type="text"
                      value={fromAmount}
                      onChange={handleFromAmountChange}
                      className="block w-full bg-transparent text-xl font-medium focus:outline-none font-mono border-none"
                      placeholder="0.0"
                    />
                  </div>
                  <div className="w-1/3">
                    <Select value={fromAsset?.symbol} onValueChange={handleFromAssetChange}>
                      <SelectTrigger className="inline-flex items-center px-3 py-2 border border-gray-300 shadow-sm text-sm font-medium rounded-lg text-gray-700 bg-white hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-emerald-500 w-full justify-between">
                        {fromAsset ? (
                          <div className="flex items-center">
                            <img src={fromAsset.icon} alt={fromAsset.symbol} className="h-6 w-6 rounded-full mr-2" />
                            <span className="font-medium">{fromAsset.symbol}</span>
                          </div>
                        ) : (
                          <span>Select</span>
                        )}
                        <ChevronDown className="h-4 w-4 opacity-70" />
                      </SelectTrigger>
                      <SelectContent>
                        {assets.map((asset) => (
                          <SelectItem key={`from-${asset.symbol}`} value={asset.symbol}>
                            <div className="flex items-center">
                              <img src={asset.icon} alt={asset.symbol} className="h-5 w-5 rounded-full mr-2" />
                              <span>{asset.symbol}</span>
                            </div>
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                </div>
                <div className="text-sm text-gray-500 flex justify-between">
                  <span>Balance: {fromAsset ? `10.5 ${fromAsset.symbol}` : "0"}</span>
                  <Button 
                    type="button" 
                    variant="ghost" 
                    className="text-emerald-600 font-medium px-2 py-1 h-auto hover:bg-emerald-50 rounded-md"
                    onClick={() => {
                      if (fromAsset) {
                        setFromAmount("1");
                        updateCalculations("1", fromAsset, toAsset);
                      }
                    }}
                  >
                    MAX
                  </Button>
                </div>
              </div>
            </div>

            <div className="flex justify-center my-3">
              <Button 
                type="button" 
                variant="outline"
                size="icon"
                className="bg-white border border-emerald-200 p-3 rounded-full text-emerald-600 hover:bg-emerald-50 transition-all duration-200 shadow-sm"
                onClick={switchAssets}
              >
                <ArrowUpDown className="h-5 w-5" />
              </Button>
            </div>

            <div className="mb-5">
              <Label className="block text-sm font-medium text-gray-700 mb-1 flex items-center">
                <span className="mr-1">You Receive</span>
                <div className="text-xs bg-blue-100 text-blue-700 px-2 py-0.5 rounded-full">To</div>
              </Label>
              <div className="bg-gray-50 rounded-lg p-4 border border-gray-200 hover:border-emerald-300 transition-colors">
                <div className="flex justify-between items-center mb-2">
                  <div className="relative w-2/3">
                    <Input
                      type="text"
                      value={toAmount}
                      className="block w-full bg-transparent text-xl font-medium focus:outline-none font-mono border-none"
                      placeholder="0.0"
                      readOnly
                    />
                  </div>
                  <div className="w-1/3">
                    <Select value={toAsset?.symbol} onValueChange={handleToAssetChange}>
                      <SelectTrigger className="inline-flex items-center px-3 py-2 border border-gray-300 shadow-sm text-sm font-medium rounded-lg text-gray-700 bg-white hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-emerald-500 w-full justify-between">
                        {toAsset ? (
                          <div className="flex items-center">
                            <img src={toAsset.icon} alt={toAsset.symbol} className="h-6 w-6 rounded-full mr-2" />
                            <span className="font-medium">{toAsset.symbol}</span>
                          </div>
                        ) : (
                          <span>Select</span>
                        )}
                        <ChevronDown className="h-4 w-4 opacity-70" />
                      </SelectTrigger>
                      <SelectContent>
                        {assets.map((asset) => (
                          <SelectItem key={`to-${asset.symbol}`} value={asset.symbol}>
                            <div className="flex items-center">
                              <img src={asset.icon} alt={asset.symbol} className="h-5 w-5 rounded-full mr-2" />
                              <span>{asset.symbol}</span>
                            </div>
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                </div>
                <div className="text-sm text-gray-500">
                  <span>Balance: {toAsset ? `1,200 ${toAsset.symbol}` : "0"}</span>
                </div>
              </div>
            </div>

            <div className="bg-emerald-50 p-4 rounded-lg mb-5 border border-emerald-100">
              <div className="flex justify-between text-sm mb-2">
                <span className="text-gray-700 flex items-center">
                  <RefreshCw className="h-4 w-4 mr-1 text-emerald-600" />
                  Exchange Rate
                </span>
                <span className="font-medium text-emerald-700">
                  {exchangeRate && fromAsset && toAsset
                    ? `1 ${fromAsset.symbol} = ${exchangeRate.toFixed(6)} ${toAsset.symbol}`
                    : "-"
                  }
                </span>
              </div>
              <div className="flex justify-between text-sm mb-2">
                <span className="text-gray-700 flex items-center">
                  <Percent className="h-4 w-4 mr-1 text-emerald-600" />
                  Price Impact
                </span>
                <span className={`font-medium px-2 py-0.5 rounded-full ${
                  priceImpact < 1 ? "bg-green-100 text-green-700" : 
                  priceImpact < 3 ? "bg-yellow-100 text-yellow-700" : "bg-red-100 text-red-700"
                }`}>
                  {priceImpact.toFixed(2)}%
                </span>
              </div>
              <div className="flex justify-between text-sm">
                <span className="text-gray-700 flex items-center">
                  <Zap className="h-4 w-4 mr-1 text-emerald-600" />
                  LP Fee
                </span>
                <span className="font-medium text-emerald-700">0.3%</span>
              </div>
            </div>

            <div className="mt-4">
              <Button 
                type={isConnected ? "submit" : "button"}
                onClick={() => !isConnected && openModal()}
                className="w-full bg-gradient-to-r from-emerald-500 to-teal-500 hover:from-emerald-600 hover:to-teal-600 text-white py-4 px-6 rounded-lg font-bold text-md transition-all duration-200 shadow-md hover:shadow-lg btn-hover-effect"
              >
                Swap Now
              </Button>
            </div>
          </form>
        </CardContent>
      </Card>
    </div>
  );
}

client/src/components/transactions-table.content:
import { useState } from "react";
import { Link } from "wouter";
import { Card, CardContent } from "@/components/ui/card";
import { CryptoIcon, DualCryptoIcon } from "@/components/ui/crypto-icon";
import { transactions } from "@/lib/mockData";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";

interface TransactionsTableProps {
  limit?: number;
  showViewAll?: boolean;
}

export default function TransactionsTable({ limit, showViewAll = false }: TransactionsTableProps) {
  const displayedTransactions = limit ? transactions.slice(0, limit) : transactions;

  // Format timestamp relative to now (e.g. "2 hours ago")
  const formatRelativeTime = (date: Date) => {
    const now = new Date();
    const diffMs = now.getTime() - date.getTime();
    const diffMins = Math.floor(diffMs / (1000 * 60));
    const diffHours = Math.floor(diffMs / (1000 * 60 * 60));
    const diffDays = Math.floor(diffMs / (1000 * 60 * 60 * 24));

    if (diffMins < 60) return `${diffMins} minute${diffMins !== 1 ? 's' : ''} ago`;
    if (diffHours < 24) return `${diffHours} hour${diffHours !== 1 ? 's' : ''} ago`;
    return `${diffDays} day${diffDays !== 1 ? 's' : ''} ago`;
  };

  return (
    <div className="mb-8">
      <div className="flex justify-between items-center mb-4">
        <h2 className="text-xl font-semibold">Recent Transactions</h2>
        {showViewAll && (
          <Link href="/history">
            <Button variant="link" className="text-primary hover:text-blue-700 text-sm font-medium p-0 h-auto">
              View All
            </Button>
          </Link>
        )}
      </div>

      <Card className="bg-white shadow-sm border border-gray-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-50">
              <tr>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Type</th>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Asset</th>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Amount</th>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Date</th>
                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Status</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {displayedTransactions.map((tx) => (
                <tr key={tx.id}>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <Badge variant="outline" className={`
                      ${tx.type === 'lend' ? 'bg-blue-100 text-blue-800' : ''}
                      ${tx.type === 'borrow' ? 'bg-purple-100 text-purple-800' : ''}
                      ${tx.type === 'swap' ? 'bg-green-100 text-green-800' : ''}
                      ${tx.type === 'interest' ? 'bg-yellow-100 text-yellow-800' : ''}
                    `}>
                      {tx.type.charAt(0).toUpperCase() + tx.type.slice(1)}
                    </Badge>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="flex items-center">
                      {tx.type === 'swap' && tx.fromAsset && tx.toAsset ? (
                        <div className="flex-shrink-0 h-6 w-6 flex">
                          <img className="h-6 w-6 rounded-full" src={tx.fromAsset.icon} alt={tx.fromAsset.symbol} />
                          <img className="h-6 w-6 rounded-full -ml-2" src={tx.toAsset.icon} alt={tx.toAsset.symbol} />
                        </div>
                      ) : (
                        <div className="flex-shrink-0 h-6 w-6">
                          <img className="h-6 w-6 rounded-full" src={tx.asset.icon} alt={tx.asset.symbol} />
                        </div>
                      )}

                      <div className="ml-3">
                        <div className="text-sm font-medium text-gray-900">
                          {tx.type === 'swap' && tx.fromAsset && tx.toAsset 
                            ? `${tx.fromAsset.symbol} → ${tx.toAsset.symbol}`
                            : `${tx.asset.name} (${tx.asset.symbol})`
                          }
                        </div>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className={`text-sm font-mono ${
                      tx.type === 'borrow' ? 'text-error' : 
                      tx.type === 'interest' ? 'text-success' : ''
                    }`}>
                      {tx.type === 'swap' && tx.fromAsset && tx.toAsset 
                        ? `${tx.amount} ${tx.fromAsset.symbol} → ${(tx.amount * tx.fromAsset.price / tx.toAsset.price).toFixed(2)} ${tx.toAsset.symbol}`
                        : `${tx.type === 'borrow' ? '-' : '+'} ${tx.amount} ${tx.asset.symbol}`
                      }
                    </div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                    {formatRelativeTime(tx.date)}
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <Badge variant="outline" className={`
                      ${tx.status === 'completed' ? 'bg-green-100 text-green-800' : ''}
                      ${tx.status === 'pending' ? 'bg-yellow-100 text-yellow-800' : ''}
                      ${tx.status === 'failed' ? 'bg-red-100 text-red-800' : ''}
                    `}>
                      {tx.status.charAt(0).toUpperCase() + tx.status.slice(1)}
                    </Badge>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </Card>
    </div>
  );
}

client/src/components/transfer-form.tsx.content:
import { useState } from "react";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { useToast } from "@/hooks/use-toast";
import { apiRequest } from "@/lib/queryClient";
import { Send, User, DollarSign } from "lucide-react";

export default function TransferForm() {
  const [recipientUsername, setRecipientUsername] = useState("");
  const [assetSymbol, setAssetSymbol] = useState("");
  const [amount, setAmount] = useState("");
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const transferMutation = useMutation({
    mutationFn: async (transferData: { recipientUsername: string; assetSymbol: string; amount: number }) => {
      const response = await apiRequest("POST", "/api/transfer", transferData);
      return response.json();
    },
    onSuccess: (data) => {
      toast({
        title: "Transfer Successful",
        description: data.message,
      });
      // Reset form
      setRecipientUsername("");
      setAssetSymbol("");
      setAmount("");
      // Refresh transactions
      queryClient.invalidateQueries({ queryKey: ["/api/transactions"] });
    },
    onError: (error: Error) => {
      toast({
        title: "Transfer Failed",
        description: error.message,
        variant: "destructive",
      });
    },
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (!recipientUsername || !assetSymbol || !amount) {
      toast({
        title: "Missing Information",
        description: "Please fill in all fields",
        variant: "destructive",
      });
      return;
    }

    const transferAmount = parseFloat(amount);
    if (isNaN(transferAmount) || transferAmount <= 0) {
      toast({
        title: "Invalid Amount",
        description: "Please enter a valid amount",
        variant: "destructive",
      });
      return;
    }

    transferMutation.mutate({
      recipientUsername,
      assetSymbol,
      amount: transferAmount
    });
  };

  return (
    <Card className="w-full max-w-md">
      <CardHeader>
        <CardTitle className="flex items-center space-x-2">
          <Send className="h-5 w-5" />
          <span>Send Funds</span>
        </CardTitle>
        <CardDescription>
          Transfer crypto assets to another user by username
        </CardDescription>
      </CardHeader>
      <CardContent>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="space-y-2">
            <Label htmlFor="recipient" className="flex items-center space-x-1">
              <User className="h-4 w-4" />
              <span>Recipient Username</span>
            </Label>
            <Input
              id="recipient"
              type="text"
              placeholder="Enter username"
              value={recipientUsername}
              onChange={(e) => setRecipientUsername(e.target.value)}
              disabled={transferMutation.isPending}
            />
          </div>

          <div className="space-y-2">
            <Label htmlFor="asset">Asset</Label>
            <Select value={assetSymbol} onValueChange={setAssetSymbol} disabled={transferMutation.isPending}>
              <SelectTrigger>
                <SelectValue placeholder="Select asset" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="BTC">Bitcoin (BTC)</SelectItem>
                <SelectItem value="ETH">Ethereum (ETH)</SelectItem>
                <SelectItem value="USDC">USD Coin (USDC)</SelectItem>
                <SelectItem value="USDT">Tether (USDT)</SelectItem>
                <SelectItem value="DAI">Dai (DAI)</SelectItem>
                <SelectItem value="LINK">Chainlink (LINK)</SelectItem>
              </SelectContent>
            </Select>
          </div>

          <div className="space-y-2">
            <Label htmlFor="amount" className="flex items-center space-x-1">
              <DollarSign className="h-4 w-4" />
              <span>Amount</span>
            </Label>
            <Input
              id="amount"
              type="number"
              step="0.000001"
              placeholder="0.00"
              value={amount}
              onChange={(e) => setAmount(e.target.value)}
              disabled={transferMutation.isPending}
            />
          </div>

          <Button 
            type="submit" 
            className="w-full" 
            disabled={transferMutation.isPending}
          >
            {transferMutation.isPending ? (
              "Sending..."
            ) : (
              <>
                <Send className="h-4 w-4 mr-2" />
                Send Transfer
              </>
            )}
          </Button>
        </form>
      </CardContent>
    </Card>
  );
}

client/src/components/wallet-banner.tsx.content:
import { useWallet } from "@/lib/walletContext";
import { Button } from "@/components/ui/button";

export default function WalletBanner() {
  const { openModal } = useWallet();

  return (
